INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('retired-10ced7e2-moex-00133', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-13504c0c', 'sub-retired-10ced7e2-02', NULL, 'single_choice', '「那天我們翻過雞籠山，居高臨下看見遠方的地平線，此時正冒出濃濃白煙，是美 國飛機剛轟炸過的基隆港。二戰已將近尾聲，從大人談話裡可聽出日軍正在節節敗 退。報紙上一再出現『決戰』字眼，他們面容竟絲毫不見憂心，不明白當了日本國 民五十年的臺灣人在心裡將自己擺在那一邊？回來以後，我好幾次夢見海上滿天都 是飛機，只慢慢移動甚至停留在海面，不時引發陣陣煙火……。又聽說有架美國 飛機落在山區，搜索隊回來時掏出好大的手錶，指針還運轉著，阿公看了有些傷感， 說：『美國手錶走的是美國時間，此時美國的家人還在等著他回去。』天未亮，隱 約聽到有女人哭泣的聲音，近午時聽說是收到未婚夫從遭攻擊的艦上，輾轉送出準 備好『全沒』的訣別書。」 下列敘述何者最接近主旨？', '["作者以孩童視角觀察戰爭中交迭的勝負", "作者疑惑大人對於日本政府的曖昧態度", "作者的家人對美軍相對期待並抱持同情", "作者的戰爭記憶中隱含了跨國族的創傷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00134', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-13504c0c', 'sub-retired-10ced7e2-02', NULL, 'single_choice', '「高音的條件，是要有寬厚充足的氣力，讓聲音上去，有飽滿的氣力來襯托，才不 會高而危薄，終不能長久。」 下列選項，何者最切合文中所表達的旨趣？', '["為高必因丘陵，為下必因川澤", "無為其所不為，無欲其所不欲", "水之積也不厚，則其負大舟也無力", "致廣大而盡精微，極高明而道中庸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00135', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-13504c0c', 'sub-retired-10ced7e2-02', NULL, 'single_choice', '「日本著名導演黑澤明的自傳用了一個奇怪的書名：《蝦蟆的油》。它來自日本的 一則民間傳說：有位醫生抓到一隻醜陋的蝦蟆，牠長有四隻前腳、六隻後腳。醫生 將蝦蟆裝進一個玻璃箱內，蝦蟆從鏡面的玻璃中，第一次看到自己醜陋的形象，嚇 得擠出一身油來。醫生收取這些油，用來治療病人的燒燙割傷，據說具有奇效。」 根據上文，下列何者最符合黑澤明傳記的命名旨趣？', '["作者自覺一生失敗難堪，猶如醜陋的蝦蟆，自慚形穢", "人世的險惡如醜陋的蝦蟆，令人驚駭莫名，細思極恐", "作者反思醜陋難堪的過往，透過書寫傳記以療傷止痛", "作者揭示自身難堪的經歷，盼能醫治讀者心靈的傷痛"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00136', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-13504c0c', 'sub-retired-10ced7e2-02', NULL, 'single_choice', '「紐曼認為大學是一個提供博雅教育，培育紳士的地方（雖然他也認為大學可以訓 練職業人才），他以為大學之目的在『傳授』學問而不在『發展』知識。他說：『如 果大學的目的在科學的與哲學的發明，那麼，我看不出為什麼大學應該有學生。』 紐曼之書為論大學之經典。他心中大學所應培育之紳士乃指通達而有修養與識見之 文化人。」 根據上文，最符合文中旨意的選項是：', '["大學最重要的目的在培育有創見的學者", "大學應以學生為重，提供優良博雅教育", "大學應該積極作為訓練職業人才的地方", "科學的與哲學的發明，是大學重要目的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00137', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-13504c0c', 'sub-retired-10ced7e2-02', NULL, 'single_choice', '「2006年3月，設計博物館與BBC舉辦大眾票選，尋找英國最愛的設計符碼，紅 色電話亭名列前茅。儘管如今它幾乎失去了原有的功能，它的歷史、設計與過往日 常生活中的地位，也使它優雅地成為英國的國家象徵，也是公共性的體現。或許在 不久的將來，紅色電話亭也會跟文書軟體上代表儲存的磁碟片圖示一樣，晦澀而遙 遠。儘管原有的功能已成歷史，然而在符碼再次轉化與詮釋的過程中，似乎還是可 以發揮新意，這點也很英國。」 根據上文，「這點也很英國」的看法，下列選項何者正確？', '["希望能在保留傳統的同時，也發展出新的創見和意涵", "偏愛晦澀且遙遠的事物，因此希望保留古老的紅色電話亭", "強調優雅與日常，而紅色電話亭的設計正是符合這樣的要求", "重視傳統與科技的平衡，希望將傳統的文化以新興的科技保存下來"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00138', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-f68e6f9e', 'sub-retired-10ced7e2-08', NULL, 'essay', '心智化（mentalization）的概念首先出現在 1960 年代法國精神病學文獻
中，以及發展心理學家對心智理論（theory of mind）的研究後開始被看
重。當成長中的嬰幼兒具有表徵心智化的能力，對於理解自我與主體的
發展有很大影響性。請說明何謂心智化？對於理解自我與主體的發展歷
程為何？請詳述之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "1cadc8f71f3c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "1013", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "心理學(包括諮商與輔導)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00139', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-f68e6f9e', 'sub-retired-10ced7e2-08', NULL, 'essay', '情緒調節（emotionalregulation）被認為是影響心理健康的重要因素，擁
有較高的情緒調節能力，能覺察自己情緒的發生原因，應用多樣化的調
整策略，適度的表達或控制情緒。而情緒調節又與依附有很大關聯。請
陳述情緒調節的內涵與類型，並對於內在運作模式（internal working
model）與情緒調節說明其關聯為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "1cadc8f71f3c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "1013", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "心理學(包括諮商與輔導)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00140', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-f68e6f9e', 'sub-retired-10ced7e2-08', NULL, 'essay', '在公部門與民眾接觸溝通頻率高，而符號溝通與語言的運用是日常人際
互動的基本要素。溝通的語言和非語言形式十分複雜，其中情緒和想法
的表達，若無法掌握其中要領，容易造成無效溝通。溝通模式約略以編
碼-解碼模式，意圖模式及觀點取替模式為主，請分別介紹此三種模式，
並就溝通過程及溝通正確性說明三種模式的異同。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "1cadc8f71f3c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "1013", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "心理學(包括諮商與輔導)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00141', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-f68e6f9e', 'sub-retired-10ced7e2-08', NULL, 'essay', '行為治療已開展到第三波（third wave），開始關注正念、接納及靈性等
議題，被視為以正念（mindfulness）與接納（acceptance）為基礎的取向。
第三波的行為治療乃圍繞著五個相關的核心議題為中心持續發展，且演
進為四個諮商理論。請說明這五個核心議題，並簡介此四個諮商理論。
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "1cadc8f71f3c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "1013", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "心理學(包括諮商與輔導)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00142', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-b96fcbef', 'sub-retired-10ced7e2-09', NULL, 'essay', '甲因精神障礙經聲請而受輔助宣告，法院選定其兄乙擔任輔助人。其父
死亡遺有土地 A、B 兩筆，甲辦理繼承登記，是否應經輔助人乙之同意？
另甲未經乙之同意，將其 C屋出售並移轉登記給丙，輔助人乙得否請求
丙返還該屋給甲？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "8ea67f012d8e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL)
